insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'Johannesburg - South Africa',
  'johannesburg-south-africa',
  '2014-01-06T04:56:18Z',
  null,
  'Two nights at the <a href="http://www.saxon.co.za">Saxon Hotel, Villas and Spa</a>... Gorgeous! As is the service!  The property, art collection, coffee delivery in conjunction with wake-up call and the rooms are a perfect reprieve after traveling so far.

The hotel was built as a private home in the Sanhurst neighborhood.  Mr Nelson Mandela stayed here for four months, after his release from prison and wrote his book A Long Road To Freedom while staying as a guest of the owner/friend (while still a private home).

We discovered that the city of  Johannesburg was founded in 1886, with along with the discovery of Gold.

The cities elevation is higher than that of Denver''s.  It sits on a plateau at 5750 ft!

The World Tree Organization gives the city the honor of being home to the largest man made forest on earth.  

UBUNTU.

Stay tuned for more from
<a href="https://edenforyourworld.com">Eden For Your World</a>, as we head to safari. <br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065428.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065428.jpg" alt="20140106-065428.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065451.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065451.jpg" alt="20140106-065451.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065516.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065516.jpg" alt="20140106-065516.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065528.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065528.jpg" alt="20140106-065528.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065541.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065541.jpg" alt="20140106-065541.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065553.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065553.jpg" alt="20140106-065553.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065602.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065602.jpg" alt="20140106-065602.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065618.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065618.jpg" alt="20140106-065618.jpg" class="alignnone size-full" /></a><br /><br /><a href="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065642.jpg"><img src="http://www.edenforyourworld.com/blog/wp-content/uploads/2014/01/20140106-065642.jpg" alt="20140106-065642.jpg" class="alignnone size-full" /></a>',
