insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'La Vie est Belle en St Barth',
  'la-vie-est-belle-en-st-barth',
  '2014-06-12T14:59:44Z',
  'Another blog about St Barth... We won''t do that to you.  There is not much more left to say about it, is there?  You know it''s in a stunning French island in the Caribbean.',
  'Another blog about St Barth... We won''t do that to you. There is not much more left to say about it, is there? You know it''s in a stunning French island in the Caribbean. You know everybody, who''s anybody takes their holiday there. You know the food is going to be amazing... it''s French!  You know everybody living on or visiting the island is, has been or will be a model. "La vie est belle" - Life is good in St Barth!

So what are you waiting for? With easy flight options and fabulous accommodations, what is keeping you from having that perfect croissant in paradise?

Contact your Eden For Your World travel advisor to start designing your holiday.

Enjoy a video of our recent stay at the beautiful <a href="http://www.letoiny.com/" target="_blank" rel="noopener noreferrer">Hotel le Toiny.</a> Click here: <a href="http://www.youtube.com/watch?v=r1GZ9qE9EGI&amp;list=UU3VQDaZsNxu8rN-UL_YEYYg" target="_blank" rel="noopener noreferrer"> St Barth Video</a>.',
  null,
  ARRAY['Beach','Caribbean','Destinations','Hotels','Island'],
  ARRAY['beach','Caribbean','destinations','hotels','Le Toiny','luxury','Luxury Travel','Saint Barthélemy','St Barth','Virtuoso'],
  'published',
  false,
  '{}',
  '[]'::jsonb
);

insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'Virtuoso Rising Star 2014',
  'virtuoso-rising-star-2014',
  '2014-07-05T17:25:03Z',
  null,
  'He did it again!  John Oberacker has been nominated by the Virtuoso luxury travel network as a Rising Star in the industry.  This is John''s second time being nominated for this prestigious award.  We couldn''t be more proud of his achievements and this honor he''s been given.  Our fingers are crossed that John''s name will be announced as the recipient of this award on August 14, 2014 at Virtuoso Travel Week in Las Vegas.

More about John:  John Oberacker caters to those looking for unique experiences around the globe.  His goal is to present the world to his clients in new, exciting and imaginative ways.   Having traveled the world extensively, 60 countries to date, he is uniquely qualified to provide his clients with first hand knowledge the destinations they want to experience.  In turn, this affords his clients wonderful memories that will last them a lifetime!  <a href="http://www.edenforyourworld.com/" target="_blank" rel="noopener noreferrer">www.edenfyw.com</a>

More about Virtuoso:  Virtuoso is the travel industry’s leading luxury network. This organization includes more than 340 agencies with 8,900 elite Advisors in 20 countries throughout North and South America, the Caribbean, Australia, and New Zealand.  Travelers who use Virtuoso’s Advisors get access to more than 1,300 of the world’s premier travel providers, as well as exclusive services, experiences, and products. <a href="http://www.virtuoso.com/" target="_blank" rel="noopener noreferrer"> http://www.virtuoso.com/</a>',
  null,
  ARRAY['Luxury Travel Shows','Press'],
  ARRAY['Best Travel Agent','destinations','eden for your world','edenforyourworld','edenfyw','inspiration','jet set','luxury','Luxury Travel','travel','travel agency','travel specialist','vacation','Virtuoso','Virtuoso Rising Star','Virtuoso Travel Week'],
  'published',
  false,
  '{}',
  '[]'::jsonb
);

insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'A Piece of Eden in Maui Hawaii',
  'a-piece-of-eden-in-maui-hawaii',
  '2014-07-16T19:21:05Z',
  null,
  'You have to LOVE a place to return to it year after year.  Maui, Hawaii, is one of those places for all three of us at Eden For Your World.  Jill has made annual pilgrimages with her family for years, as have John and I.  We all feel like it''s our second home.

What''s not to love about this island that has something for everybody?  You can simply lie on one of it''s gorgeous golden sand beaches and play in the water, or you can enjoy the myriad of activities that Maui has to offer; hike tropical jungles, swim in secluded pools fed by waterfalls, deep sea fish, whale watch, bike down a 13,000 ft volcano, zip-line, go wine or vodka tasting, visit lavender fields, eat to your hearts content, kayak with dolphins, kite surf one of the world''s best spots, immerse yourself in Hawaiian culture and music, relax by your resort pool and order Mai Tai after Mai Tai and much, much more.

This most recent visit was our 17 or 18th... we can''t keep track anymore.  Maui is never the same place twice, because it''s always changing, as we are.  But, this year was particularly special in the world of luxury hotels.  Two beautiful Virtuoso hotels had arrived for us to experience, and now we can share them with our clients.

<strong>New Luxury Hotels:</strong>

<strong>Montage Kapalua Bay</strong>

<span class="Normal">Montage Kapalua Bay celebrates art and artisanship in many forms, from architecture and local art to culinary and spa offerings, all </span><span class="Normal">inspired by the rich surroundings and culture of Hawaii. Set beachfront atop picturesque Kapalua Bay, the 24 acre-resort features Montage </span><span class="Normal">branded residences and the introduction of an intimate 50 suite Montage resort which opened in June 2014.</span>

<span class="Normal">Situated on a legendary oceanfront location, which was once the site of The Kapalua Bay Hotel, Montage Kapalua Bay offers access to the </span><span class="Normal">best of Maui. Guests experience a blend of relaxation and rejuvenation with every detail celebrating the richness of Hawaiian culture.</span>

<span class="Normal">Lasting memories can be made while relaxing by the multi-tiered lagoon pool which cascades down the center of the resort, or while dining </span><span class="Normal">on island-inspired cuisine in one of the resort’s restaurants or lounges. Comfortable all-suite accommodations are a resplendent retreat in </span><span class="Normal">themselves, with spacious living rooms, large private lanais, fully equipped kitchens, elegant master suites and luxurious bathrooms.  The <span class="indent"><span class="Normal">50 luxury residential style suites, ranging from one to four bedrooms, offer spacious living </span><span class="Normal">accommodations flowing into a large private “lanai” (balcony).</span></span>
</span>

EFYW guests will receive:
<ul>
	<li class="programOption">Upgrade at time of booking, subject to availability.</li>
	<li class="programOption">$50 Daily breakfast credit per bedroom.</li>
	<li class="programOption">$150 Spa Montage Kapalua Bay Spa service credit.</li>
	<li class="programOption">Early check-in/late check-out, subject to availability.</li>
</ul>
<strong>Andaz Maui</strong>

<span class="Normal"><span class="indent"><span class="Normal">Set along 15 acres of beachfront beauty in Wailea, awaits a new lifestyle experience, where you can dip your </span><span class="Normal">toes in the sand, explore Hawaii’s vast wonders, or lounge poolside with your favorite drink. Discover regional dishes that showcase the </span><span class="Normal">best of Maui and uncover something new every day, whether you’re here on honeymoon or booking a well-deserved vacation package. </span><span class="Normal">Gentle ocean breezes and the pristine shores of Mokapu Beach provide the perfect backdrop.</span></span></span>

<span class="Normal">From the moment you step into your room at Andaz Maui at Wailea, you’ll feel like you’re a world away. Each one of the hotel''s 290 guest </span><span class="Normal">rooms and suites, and seven residential villas, blends the non-traditional Andaz style with the feel of a luxury resort community. </span><span class="Normal">Accommodations are enhanced at every turn, with modern touches like private lanais for admiring magnificent Hawaii sunsets, baths with </span><span class="Normal">ocean and garden view showers, and luxurious body products that invigorate both body and mind.</span>

<span class="Normal">Discover your personal spa. Non-traditional and wholly unique, `āwili spa and salon invites you to mix, blend and entwine the purest </span><span class="Normal">elements of Maui into an experience that’s custom tailored to you. Let our apothecary consultants assist in blending your personal product </span><span class="Normal">for your spa or salon service, embracing your body’s truest needs and desires through an omakase treatment menu that highlights the best </span><span class="Normal">of Wailea.</span>

Oh, and be sure to get your chef''s table reserved at Ka''Ana Kitchen!  By far, one of the best meals we''ve ever had on the islands!  Everything on the menu is locally grown, raised and made.  ONO!

EFYW guests will receive:
<ul>
	<li class="programOption">Upgrade on arrival, subject to availability.</li>
	<li class="programOption">Daily full breakfast, for up to two in room guests, served in Ka''ana Kitchen.</li>
	<li class="programOption">$100 USD Spa Services credit, to be utilized during stay, (not combinable, no cash value if not redeemed in full).</li>
	<li class="programOption">Early check-in/late check-out, subject to availability.</li>
</ul>
<strong>Dining spots we loved on this trip:</strong>
<ul>
	<li>Merriman''s - Best spot on the West side for waterfront cocktails and dining.</li>
	<li>The Plantation House - Fantastic panoramic from the top of the golf course.</li>
	<li>Star Noodle - Great tapas style asian fusion dishes.</li>
	<li>Honu - Another great waterfront spot with delicious salads, pizza and fish.</li>
	<li>Vietnamese Cuisine - Yes, that is the name.  One of our favorite spots on the island!</li>
	<li>Coconuts Fish Cafe - Delicious fish tacos.  Warning:  they''re huge!</li>
	<li>Ka''Ana Kitchen - At the Andaz Waile.  DO NOT MISS THIS!</li>
	<li>Izakaya Matsu - If you''re done with giant saucy sushi rolls, this is your place.  Oishi food.</li>
	<li>Ko - At the Kea Lani.  Always great food.  Have to try the Ahi on a Rock.</li>
	<li>Isana - We love a good Korean BBQ.  Here it is.  The poke is awesome here too!</li>
</ul>
<strong>Enjoy our Maui video, by clicking on the link:  <a href="http://youtu.be/H25svc7RzzE?list=UU3VQDaZsNxu8rN-UL_YEYYg" target="_blank" rel="noopener noreferrer">Maui</a>.</strong>

Contact us to plan your next visit.  You have two Hawaii Destination Specialists standing by to make the most out of your aloha vacation.

John@EdenFYW.com or Jill@EdenFYW.com.

Aloha.

