insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'Travel Capsule Wardrobe by @Sin60Style',
  'travel-capsule-wardrobe-by-sin60style',
  '2018-03-09T14:57:45Z',
  'Eden For Your World is thrilled to announce our newest collaboration with stylist Cynthia Pastor, of the popular Instagram @sin60style.',
  '[vc_row css_animation="" row_type="row" use_row_as_full_screen_section="no" type="full_width" angled_section="no" text_align="left" background_image_as_pattern="without_pattern"][vc_column][vc_column_text]<strong>Cinderella never asked for a prince. She asked for a night off and a dress. ~ Kiera Cass</strong>

Eden For Your World is thrilled to announce our newest collaboration with stylist Cynthia Pastor, of the popular Instagram <span style="color: #993300;"><a style="color: #993300;" href="https://www.instagram.com/sin60style/?hl=en" target="_blank" rel="noopener noreferrer">@sin60style</a></span>. Cynthia is a longtime client turned friend, who specializes in capsule collection wardrobe styling. A capsule collection is a curated assortment of clothing that can be mixed and matched in multiple different ways, creating many looks out of a limited number of items.

When the opportunity arose to partner with Cynthia to bring ease and convenience to our beloved clientele, we knew we could not pass it up. While Eden For Your World takes all of the stress and planning off your hands in creating your perfect getaway, the packing burden falls on your shoulders. Enter Cynthia, a professional stylist and master mixer. She will curate the perfect “travel capsule wardrobe” for you, your family, partner, children, etc. so that you can fully enjoy every aspect of travel. After a brief consultation and discussion of wardrobe needs, Cynthia will create your travel wardrobe for you, complete with detailed photos. How can it get any easier?

To learn more about Cynthia, please visit her website at <span style="color: #993300;"><a style="color: #993300;" href="http://www.cynthiapastor.com" target="_blank" rel="nofollow noopener noreferrer">www.cynthiapastor.com</a></span>. For bookings, please email us at info@edenforyourworld.com or just tell Cynthia that #EdenFYW sent you to receive added benefits.
<div></div>
[/vc_column_text][vc_empty_space][vc_gallery interval="3" images="1532,1533,1534,1535" img_size="1200x700" direction_nav="yes" control_nav="yes"][/vc_column][/vc_row]',
