insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'Peru',
  'peru',
  '2018-04-18T15:37:48Z',
  'A prophet once said ‘Don’t tell me what a man says, don’t tell me what a man knows. Tell me where he’s traveled?’ I wonder about that, do we get smarter, more enlightenment as we travel? Does travel bring wisdom? I think there is probably no better place to find out than Peru. ~ Anthony Bourdain',
  '[vc_row css_animation="" row_type="row" use_row_as_full_screen_section="no" type="full_width" angled_section="no" text_align="left" background_image_as_pattern="without_pattern"][vc_column][vc_column_text]<strong>A prophet once said ‘Don’t tell me what a man says, don’t tell me what a man knows. Tell me where he’s traveled?’ I wonder about that, do we get smarter, more enlightenment as we travel? Does travel bring wisdom? I think there is probably no better place to find out than Peru. ~ Anthony Bourdain</strong>

Eden For Your World travel advisor Kim Diaz had been dreaming of the perfect way to celebrate her husband''s birthday. A trip to experience a bucket list destination for her whole family was the winning idea... so the whole family set off to see Machu Pichu and beyond! Their quick Spring Break ''18 getaway will be one they''ll never forget. Read about it below, in excerpts from her travel diary.

<strong>Day 1:</strong>  Lima - After an all night flight and a brief nap we ventured off to the Museo Larco which is a beautiful, must see, museum with 5000 years of Peruvian history housed in a magnificent 18th century vice-royalty mansion. The gardens alone are worth a visit and we highly recommend making reservations at the restaurant on site.  Not only is the atmosphere perfect, the food was equally matched. A walk around the Miraflores coastline was the end to a perfect first day.

<strong>Day 2:</strong> Our tour guide picked us up for a full day tour of Lima Highlights. We walked through the Barranca neighborhood enjoying the wall murals and hipster bohemian vibe, then we headed to the Matte Museum, we ended the day with a delicious dinner (we tried Cuy...a Peruvian favorite!) overlooking ruins at Huaca Pullana.

<strong>Day 3:</strong> After a short flight we landed in Cusco where we were greeted by locals offering cacao leaves to aid in adjusting to the altitude. Once outside the airport it''s hard to tell what is taking your breath away-the altitude or the back drop of beautiful kelly green mountains as far as you can see with the locals adorned in vibrant colored clothing. We wound through the mountains to the Sacred Valley, stopping at a picturesque spot which allowed us to feed the llamas and alpacas alfalfa while we enjoyed a delicious boxed lunch. Meandering through a local marketplace in Pisac and a short hike to the ruins was the end to a perfect day. We arrived at our hotel the Inkaterra Hacienda Urubamba at dusk which left all of us oohing and aahing. Tucked in the Sacred Valley it is a little piece of heaven. Fires going throughout the hotel including our individual rooms, a refreshing Pisco Sour on a silver tray waiting upon arrival, and the entire staff there to fulfill any request, made this entire experience EdenFYW!

<strong>Day 4:</strong>  A hike at Ollantaytamba, Incan ruins, found us viewing breathtaking scenery for another day. You can never get enough. Our guide warned us (as we were huffing and puffing) this was good practice for Macchu Picchu. Uh oh! A short drive away were the salt ponds of Maras. Hungry for lunch we arrived at non-descript door on small cobble stoned street in a little town called Mooray.  Once the door opened, we were greeted by the owner of the home and his wife and welcomed into a beautiful oasis. Gardens of fruits, vegetables and herbs surrounded the home that looked out to another perfect view. Inside, they served us a 3 course organic lunch with true Peruvian hospitality. A unique one-of-a-kind experience.

<strong>Day 5 and 6:</strong> Belmond''s Hiram Bingham train to Machu Picchu....enough said! Definitely EdenFYW!

<strong>Day 7 and 8:</strong> Cusco

A city filled with history and charm.  Churches, ruins, restaurants and a wonderful mix of new and old. We stayed at the Palacio del Inka a Luxury Collection Hotel. Service was again, top notch and the breakfast buffet was one of the best we''ve ever had. A unique historic property that we highly recommend! Saqsaywaman Ruins were the highlight of the day and we stopped to purchase handmade Peruvian dolls to bring home to our nieces.

<strong>Day 9:</strong> Upon waiting for our flight to head back to Los Angeles my whole family agreed that this was one of our favorite vacations. The sights-spectacular, the people-friendly, the food-delicious, the activities -unique! A must  on everyone''s bucket list.

Peru...A magical destination, for one and all! ~ Kim Diaz

[/vc_column_text][vc_empty_space][vc_gallery interval="3" images="1496,1497,1498,1499,1500,1501,1502,1503,1504,1505" img_size="1200x700" direction_nav="yes" control_nav="yes"][/vc_column][/vc_row]',
  null,
  ARRAY['Destinations','Family Travel','Hotels','South America','Travel Quotes','Travel Tips'],
  ARRAY['ancient','archeology','bucket list','Cusco','eden for your world','edenfyw','Family Getaway','family travel','Inca','Machu Pichu','Peru','Sacred Valley','South America','Virtuoso Travel'],
  'published',
  false,
  '{}',
  '[]'::jsonb
);

insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'Turkey - An EdenFYW Traveler''s View',
  'turkey-an-edenfyw-travelers-view',
  '2018-05-14T22:35:13Z',
  'Please put away any preconceived ideas you have about the country of Turkey! My husband and I recently visited Istanbul, Cappadocia, and Izmir. In a nutshell, it is very safe and incredibly clean.',
  '[vc_row css_animation="" row_type="row" use_row_as_full_screen_section="no" type="full_width" angled_section="no" text_align="left" background_image_as_pattern="without_pattern"][vc_column][vc_column_text]<strong>A man who doesn''t think differently from his time and environment can''t grow beyond his time and environment. ~ Mustafa Kemal Ataturk</strong>

Please enjoy the following guest blog post from our dear client Mrs. Felicia G., who traveled to Turkey in April of 2018 with her husband.

Please put away any preconceived ideas you have about the country of Turkey! My husband and I recently visited Istanbul, Cappodocia and Izmir. In a nutshell, it is very safe and indredibly clean. The people of Turkey are warm, well educated, hospitable and excepting of all cultures. They also very much like Americans and the US, and almost everyone we spoke to had either been to the states or had a family member living in California.

The historical sites such as Hagia Sofia, the Blue Mosque, and the Galata Tower in Istanbul will transport you to a time of ancient civilizations and their citizenry. The sites are easy to tackle and the transportation system in Turkey is very user friendly. Istanbul is a very modern city not unlike Paris for its museums and cultural offerings. The food is delicious and a visitor would have to make an effort to have a bad meal here!  I recommend a guide, and EdenFYW hooked us up with the best in every city we visited. I particularly like the shopping in the Grand Bazaar and Spice Market. If you can recall from world history class, ancient Turkey was an integral part of the Silk Road which stretched from China through India, Turkey, Egypt parts of the African continent through Greece, Rome and Britain. The artisans and merchants of Turkey are well known for their rugs and textiles and we purchased several from the Turkish cooperatives we visited and we had fun bargaining with all of the various merchants who were very respectful if you decided against a particular item.

In Cappodocia, our hotel was luxurious as were all of them throughout the country.  We were scheduled for a balloon ride to see the geography of the area for which this region is know...the fairy chimneys. This is a must do. We were able to see how people lived in the caves in the local area, and in one such cave it was the owners grandparent''s home and he has made it his studio and souvenir shop. We missed the Argos castle unfortunately due to time but I always like to leave something for another visit. Again the people of the town were so hospitable and did everything they could to make your visit memorable.

Izmir, on the Agean Sea, is the gateway to the largest set of ruins of Ancient Rome and is a World Heritage Site. Our hotel was super high tech and we had a fantastic view of the water. Our guide was top-notch and even recommended some great places to dine after the sites of the day.  Once again EdenFYW did their magic. We definitely did not spend enough time here and am hoping to return!

All I can say to you is GO!  By the way, the dollar is very strong these days which made our trip even more enjoyable!
<div></div>
<div></div>
[/vc_column_text][vc_empty_space][vc_gallery interval="3" images="1487,1488,1489,1490,1491,1492" img_size="full" direction_nav="yes" control_nav="yes"][/vc_column][/vc_row]',
  null,
  ARRAY['Adventure','Art','Asia','Beach','Destinations','Europe','Family Travel','Hotels','Style','Travel Quotes','Travel Tips'],
  ARRAY['Asia','Cappodocia','eden for your world','edenfyw','Europe','Istanbul','Luxury Travel','travel','travel tips','Turkey','Virtuoso Travel'],
  'published',
  false,
  '{}',
  '[]'::jsonb
);

insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'John Oberacker of Eden for Your World Wins Virtuoso 2018 Most Innovative Advisor Award',
  'john-oberacker-of-eden-for-your-world-wins-virtuoso-2018-most-innovative-advisor-award',
  '2018-08-21T17:48:45Z',
  'Global luxury travel network Virtuoso® congratulates John Oberacker of Eden For Your World, an independent affiliate of Montecito Village Travel, in Long Beach, California as the winner of this year’s sought-after Most Innovative Travel Advisor US & Canada at the 30th annual Virtuoso Travel Week.',
  'LAS VEGAS (August 16, 2018) – Global luxury travel network Virtuoso® congratulates John Oberacker of Eden For Your World, an independent affiliate of Montecito Village Travel, in Long Beach, California as the winner of this year’s sought-after Most Innovative Travel Advisor US &amp; Canada at the 30th annual Virtuoso Travel Week. Oberacker received the award during the Virtuoso 30th Anniversary Awards Gala on August 16, 2018 at The Bellagio Luxury Resort in Las Vegas. The accolade is especially noteworthy as only a fraction of the network’s 17,500 advisors and 1,000-plus agency members are honored at Virtuoso Travel Week.

John Oberacker’s achievements, including exceptional innovation, thorough knowledge and superior service, have helped Virtuoso become the industry-leading network it is today,” said David Kolner, senior vice president, Global Member Partnerships at Virtuoso. “This network is respected for the high caliber of its members, and the close relationships they enjoy with our partners. As one of our exclusive award winners, John Oberacker is enhancing Virtuoso’s reputation as a trailblazer in the luxury travel industry, providing the network with a competitive edge in serving savvy global travelers.”

John is delighted to have received this recognition from the thousands of luxury travel suppliers from around the world, all of whom he credits for helping achieve this honor.

<strong>About Eden for Your World
</strong>

John Oberacker and Kasra Esteghamat have been successful business partners for over 17 years.  Their honesty and dedication has yielded them a large and loyal client base, and their energy and loyalty has produced a team of unlimited resources around the world.  Their boutique luxury travel agency, Eden For Your World, is a natural extension of their desires to share their expertise of all things ‘eden’ from around the world. For more information, visit <a href="http://www.edenforyourworld.com" target="_blank" rel="noopener noreferrer">www.edenforyourworld.com</a>.

<strong>About Virtuoso</strong>

<strong>Virtuoso<sup>®</sup> </strong>is the leading international travel agency network specializing in luxury and experiential travel. This by-invitation-only organization comprises over 1,000 travel agency partners with 17,500 elite travel advisors in 50 countries throughout North America, Latin America, the Caribbean, Europe, Asia-Pacific, Africa and the Middle East. Drawing upon its preferred relationships with 1,700 of the world’s best hotels and resorts, cruise lines, airlines, tour companies and premier destinations, the network provides its upscale clientele with exclusive amenities, rare experiences and privileged access. More than (U.S.) $23.7 billion in annual travel sales makes Virtuoso a powerhouse in the luxury travel industry. For more information, visit <a href="http://www.virtuoso.com/">www.virtuoso.com</a>.

&nbsp;',
  null,
  ARRAY['Press'],
  ARRAY['#virtuosotravel','award','eden for your world','Luxury Travel','Most Innovative Advisor','travel','Virtuoso Travel'],
  'published',
  false,
  '{}',
  '[]'::jsonb
);

insert into public.blog_posts
  (agent_id, title, slug, published_at, excerpt, body_html, cover_image_url, categories, tags, status, is_broadcast, target_agent_ids, gallery_images)
values (
  '14385e4b-7dbe-4642-88b8-1a1a0279f5d2',
  'John Oberacker: How Virtuoso’s Most Innovative Advisor Stays Ahead of the Curve',
  'john-oberacker-how-virtuosos-most-innovative-advisor-stays-ahead-of-the-curve',
  '2018-10-01T16:56:26Z',
  'Staying ahead of the curve in the luxury travel industry and setting the trends instead of following them is a tall order — especially when the definition of “luxury” is ever-changing — but it’s what makes the advisors who pull it off so special.',
  '[vc_row css_animation="" row_type="row" use_row_as_full_screen_section="no" type="full_width" angled_section="no" text_align="left" background_image_as_pattern="without_pattern"][vc_column][vc_column_text]Staying ahead of the curve in the luxury travel industry and setting the trends instead of following them is a tall order — especially when the definition of “luxury” is ever-changing — but it’s what makes the advisors who pull it off so special.

Enter John Oberacker, founder and CEO of <a href="http://www.edenforyourworld.com/">Eden for Your World</a>, an affiliate of Montecito Village Travel in Long Beach, CA.

In August, Oberacker was named Virtuoso’s most innovative advisor, which the luxury travel network defines as the “travel advisor [who] has demonstrated the most innovative, imaginative and out-of-the-box thinking in selling travel.” It was the second year in a row that Oberacker was nominated for the award and his fourth nomination by Virtuoso in total (the previous two were for Virtuoso’s Rising Star, the “person, in the early stages of her or his career, [who] exhibits exceptional promise for reaching an elite level of professionalism and achievement”).

<strong>Read more: <a href="https://www.luxurytraveladvisor.com/people/john-oberacker" target="_blank" rel="noopener noreferrer">https://www.luxurytraveladvisor.com/people/john-oberacker</a></strong>[/vc_column_text][vc_empty_space][vc_gallery interval="3" images="1483,1484" img_size="full" direction_nav="yes" control_nav="yes"][/vc_column][/vc_row]',
  null,
  ARRAY['Press','Travel Tips'],
  ARRAY['#virtuosotravel','edenfyw','Luxury Travel','luxurytraveladvisor','travel','travel advisor','travel magazine'],
  'published',
  false,
  '{}',
  '[]'::jsonb
);

